INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (1,'2020-09-09 00:00:00','2020-09-09 00:00:00',1,1,'1',' Mathematics Introduction ','MATHS','https://www.youtube.com/embed/wTV9PHlD-tU');
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (2,'2020-09-10 00:00:00','2020-09-10 00:00:00',1,1,'When you hear the word Science, what comes to your mind? Lab coats and test tubes?\nTelescopes and stars? Einstein? Dog-eared textbooks? While all of these represent\nvarious aspects of science, none truly embodies the subject as a whole. The reason\nbeing it is multifaceted. So, come, join us and explore the world of science and miracles\nwith our online Science Classes.',' Science Introduction ','SCIENCE','https://www.youtube.com/embed/r6KNcnysgtY');
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (3,'2020-09-11 00:00:00','2020-09-11 00:00:00',1,1,'While some interpret this subject as a status symbol, others often term it as a mere\nlanguage. But irrespective of whatever it is, with a reach so far and wide, it is something\nthat is socially acclaimed. So, why not learn it from the best? Get access to interesting\nstories, poems, novels, and many more, all under one roof in our English online classes.\nBecause English is not only a language but an expression.','English Introduction ','ENGLISH','https://www.youtube.com/embed/BBCh9z9ifU8');
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (4,'2020-09-12 00:00:00','2020-09-12 00:00:00',1,1,'Every language has a beauty of its own and Kannada is no different. Understand the\nnuances and the beauty of Kannada with the help of our innovative videos and live\nclasses. Sign in to our online Kannada classes and get access to interesting stories,\npoems, and novels. Because no language is foreign if you learn with Vista’s Learning',' Kannada Introduction ','ಕನ್ನಡ ','https://www.youtube.com/embed/bnWTt29m9-s');
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (5,'2020-09-13 00:00:00','2020-09-13 00:00:00',1,1,'India has 22 official languages that are spoken far and wide all over the country. But\nHindi is one such language that is commonly used, pretty much everywhere, in India.\nSo, if you are keen on Hindi and wish to increase your brilliance in Hindi skills and\nliterature, learn Hindi online with our educational videos and live sessions where you get\naccess to beautiful stories, novels and poems, all written in Hindi.',' Hindi Introduction ','हिंदी','https://www.youtube.com/embed/bnWTt29m9-s');
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (6,'2020-09-16 00:00:00','2020-09-16 00:00:00',1,1,'Social Science is an archive of the past, an overview of the environment we live in, and\nan outlook of our society as a whole. But often, this subject is subjected to criticisms,\nlike being dull and lengthy. But not anymore, because we bring you innovative videos\nand live sessions to clear your doubts and to make the process of learning even more\ninteresting for you. So, what are you waiting for? Sign in to our online classes for social\nscience and delve deep into the sea of knowledge.','Social Science Introduction ','SOCIAL SCIENCE','https://www.youtube.com/embed/bnWTt29m9-s');
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (7,'2020-09-16 00:00:00','2020-09-16 00:00:00',1,1,'evs is concerned with the exploration, investigation and development of an understanding of the natural, human, social and cultural dimensions of local and wider environments.','EVS introduction','EVS',NULL);
INSERT INTO `subject` (`idsubject`,`created_at`,`updated_at`,`created_by`,`updated_by`,`description`,`header`,`subject_name`,`video_url`) VALUES (10,'2020-09-16 00:00:00','2020-09-16 00:00:00',1,1,NULL,NULL,'NA',NULL);
INSERT INTO `subject` (`idsubject`, `created_at`, `updated_at`, `created_by`, `updated_by`, `description`, `header`, `subject_name`, `video_url`) VALUES (11, '2020-09-16 00:00:00', '2020-09-16 00:00:00', '1', '1', 'piano, also called pianoforte, French piano or pianoforte, German Klavier, a keyboard musical instrument having wire strings that sound when struck by felt-covered hammers operated from a keyboard. The standard modern piano contains 88 keys and has a compass of seven full octaves plus a few keys.', 'Piano Introduction', 'PIANO', 'https://www.youtube.com/embed/827jmswqnEA');
INSERT INTO `subject` (`idsubject`, `created_at`, `updated_at`, `created_by`, `updated_by`, `description`, `header`, `subject_name`, `video_url`) VALUES (12, '2020-09-16 00:00:00', '2020-09-16 00:00:00', '1', '1', 'Dance, the movement of the body in a rhythmic way, usually to music and within a given space, for the purpose of expressing an idea or emotion, releasing energy, or simply taking delight in the movement itself.', 'Dance Introduction', 'DANCE', 'https://www.youtube.com/embed/fP_IZKfc4vo');
INSERT INTO `subject` (`idsubject`, `created_at`, `updated_at`, `created_by`, `updated_by`, `description`, `header`, `subject_name`, `video_url`) VALUES (13, '2020-09-16 00:00:00', '2020-09-16 00:00:00', '1', '1', 'Drawing, the art or technique of producing images on a surface, usually paper, by means of marks, usually of ink, graphite, chalk, charcoal, or crayon. ... This definition, however, applies to all graphic arts and techniques that are characterized by an emphasis on form or shape rather than mass and color, as in painting.', 'Drawing Introduction', 'DRAWING', 'https://www.youtube.com/embed/aDP0WqY1MRU');
INSERT INTO `subject` (`idsubject`, `created_at`, `updated_at`, `created_by`, `updated_by`, `description`, `header`, `subject_name`, `video_url`) VALUES (14, '2020-09-16 00:00:00', '2020-09-16 00:00:00', '1', '1', 'The guitar is a string instrument which is played by plucking the strings. The main parts of a guitar are the body, the fretboard, the headstock and the strings. Guitars are usually made from wood or plastic. ... The left hand holds the neck of the guitar while the fingers pluck the strings.', 'Guitar Introduction', 'GUITAR', 'https://www.youtube.com/embed/BBz-Jyr23M4');
INSERT INTO `subject` (`idsubject`, `created_at`, `updated_at`, `created_by`, `updated_by`, `description`, `header`, `subject_name`, `video_url`) VALUES (15, '2020-09-16 00:00:00', '2020-09-16 00:00:00', '1', '1', 'painting, the expression of ideas and emotions, with the creation of certain aesthetic qualities, in a two-dimensional visual language. The elements of this language—its shapes, lines, colours, tones, and textures—are used in various ways to produce sensations of volume, space, movement, and light on a flat surface.', 'Painting Introduction', 'PAINTING', 'https://www.youtube.com/embed/SHKtV9rsy8k');
